import requests

S2_API = "https://api.semanticscholar.org/graph/v1"

def search_s2(query, fields=None):
    """Search for papers"""
    fields = fields or "title,authors,abstract,year,citationCount,externalIds"
    params = {"query": query, "fields": fields, "limit": 5}
    r = requests.get(f"{S2_API}/paper/search", params=params, timeout=15)
    if r.status_code == 200:
        return r.json().get("data", [])
    return []

# Search for Attention Is All You Need
results = search_s2("Attention Is All You Need Vaswani")
for p in results:
    ids = p.get("externalIds", {})
    print(f"Title: {p['title']}")
    print(f"  Year: {p.get('year')}, Citations: {p.get('citationCount')}")
    print(f"  ExternalIds: {ids}")
    print()
"}

