import requests
from html.parser import HTMLParser

class ArxivRefParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.in_references = False
        self.references = []
        self.current_ref = []
        self.in_ref_item = False
        self.depth = 0

    def handle_starttag(self, tag, attrs):
        attrs_dict = dict(attrs)
        if 'blockquote' in attrs_dict.get('class', ''):
            self.depth += 1
        if 'dt' in attrs_dict.get('class', ''):
            self.in_ref_item = True
            self.current_ref = []
        if 'dd' in attrs_dict.get('class', ''):
            self.in_ref_item = True

    def handle_endtag(self, tag):
        if 'blockquote' in getattr(self, '_tag_class', ''):
            self.depth -= 1
        if tag == 'dd' and self.in_ref_item:
            self.in_ref_item = False

    def handle_data(self, data):
        if self.in_ref_item and data.strip():
            self.current_ref.append(data.strip())

# Fetch arXiv abstract page
r = requests.get("https://arxiv.org/abs/1706.03762", headers={"User-Agent": "Mozilla/5.0"}, timeout=15)
print(f"Status: {r.status_code}, length: {len(r.text)}")

